import{_ as a,o as i,c as t,ag as o}from"./chunks/framework.DjqkqlVQ.js";const m=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"en/mods/sts2-god-mod/changelog.md","filePath":"en/mods/sts2-god-mod/changelog.md","lastUpdated":1778385703000}'),l={name:"en/mods/sts2-god-mod/changelog.md"};function n(r,e,d,s,c,h){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>Player-facing release notes for STS2 God Mod. The project page currently shows version <code>1.5.6</code>; the notes here are synced from the mod&#39;s in-code update notes through <code>v1.5.6</code>.</p><h2 id="v1-5-6" tabindex="-1">v1.5.6 <a class="header-anchor" href="#v1-5-6" aria-label="Permalink to &quot;v1.5.6&quot;">​</a></h2><ul><li>Faster list editing: double-click a current card to upgrade it, triple-click current cards/relics/potions to remove them, and triple-click catalog items to add them.</li><li>Fixed a stable-build issue where enabling Ancient relic refresh could leave the Neow room on a black screen.</li><li>Improved beta-build compatibility around the Neow room, Ancient rooms, and the <code>G</code> panel.</li><li>Added a <code>+10</code> block combat shortcut and a current block field in resource editing.</li><li>You can now raise the maximum hand size above 10.</li><li>Resource inputs and buttons are more compact, with a two-column layout on wide panels and one-column fallback on narrow panels.</li></ul><h2 id="v1-5-5" tabindex="-1">v1.5.5 <a class="header-anchor" href="#v1-5-5" aria-label="Permalink to &quot;v1.5.5&quot;">​</a></h2><ul><li>The <code>G</code> panel now opens correctly on the beta build.</li><li>Ancient/Neow option refreshes avoid invalid relic pairings.</li><li>Fixed cases where the first Neow room could stop before the next choices appeared.</li></ul><h2 id="v1-5-4" tabindex="-1">v1.5.4 <a class="header-anchor" href="#v1-5-4" aria-label="Permalink to &quot;v1.5.4&quot;">​</a></h2><ul><li>Added a new Expert Mode for mixed-install multiplayer, so higher-risk testing or setup changes can temporarily lift God Mod&#39;s mixed-install safety restrictions when needed.</li><li>To reduce accidental desync risk, Expert Mode automatically resets to off whenever a new run starts.</li></ul><h2 id="v1-5-3" tabindex="-1">v1.5.3 <a class="header-anchor" href="#v1-5-3" aria-label="Permalink to &quot;v1.5.3&quot;">​</a></h2><ul><li>Floating <code>G</code> button recovery is more reliable.</li><li>Fixed cases where the floating <code>G</code> button could disappear after restarting when edge snap, very low opacity, or visibility toggles were combined.</li></ul><h2 id="v1-5-2" tabindex="-1">v1.5.2 <a class="header-anchor" href="#v1-5-2" aria-label="Permalink to &quot;v1.5.2&quot;">​</a></h2><ul><li>Fixed a black screen caused by relic info lookup failure on first run start.</li><li>Ancient event handling is more reliable.</li></ul><h2 id="v1-5-1" tabindex="-1">v1.5.1 <a class="header-anchor" href="#v1-5-1" aria-label="Permalink to &quot;v1.5.1&quot;">​</a></h2><ul><li>More flexible deck management outside combat in mixed-install mode.</li><li>During combat, mixed-install compatibility still limits card editing to Hand for safer synchronization.</li><li>Outside combat, you can switch the pile selector back to Deck to inspect and organize your deck cards more easily.</li></ul><h2 id="v1-5-0" tabindex="-1">v1.5.0 <a class="header-anchor" href="#v1-5-0" aria-label="Permalink to &quot;v1.5.0&quot;">​</a></h2><ul><li>Added 6 more UI language options: Traditional Chinese, Japanese, Korean, Russian, Spanish, and Brazilian Portuguese.</li><li>Mixed-install multiplayer now also supports +5 Energy, +5 Stars, Draw Cards, Full Heal, and Kill All Enemies.</li><li>While mixed-install compatibility mode is active, card management is limited to Hand and the pile selector is forced to Hand.</li><li>You can now add hand cards, remove hand cards, upgrade hand cards, and apply hand-card enchantments.</li></ul><h2 id="v1-4-3" tabindex="-1">v1.4.3 <a class="header-anchor" href="#v1-4-3" aria-label="Permalink to &quot;v1.4.3&quot;">​</a></h2><ul><li>More stable mixed-install multiplayer.</li><li>Mixed-install multiplayer is now safer and more stable when players are not all on the same God Mod version, with clearer compatibility messaging in the lobby.</li></ul><h2 id="v1-4-2" tabindex="-1">v1.4.2 <a class="header-anchor" href="#v1-4-2" aria-label="Permalink to &quot;v1.4.2&quot;">​</a></h2><ul><li>Added a reset entry in Other Settings and Mod Config to restore local God Mod settings back to defaults.</li><li>The reset flow now includes a second confirmation to help prevent accidental deletion of local settings and custom presets.</li><li>You can now rebind the panel toggle hotkey and the room-restart hotkey in Other Settings, and adjust their long-press trigger durations separately.</li><li>To avoid conflicts, these two long-press actions must use different keys.</li></ul><h2 id="v1-4-1" tabindex="-1">v1.4.1 <a class="header-anchor" href="#v1-4-1" aria-label="Permalink to &quot;v1.4.1&quot;">​</a></h2><ul><li>Fixed the multiplayer campfire extra-remove flow so it is generated through the native rest-site option list, uses the correct owner player, and no longer consumes the entire campfire turn after removing a card.</li><li>Fixed missing icon and localization follow-up issues that could break the rest-site sync flow, prevent the remove button from updating correctly, or lead to downstream multiplayer desyncs after leaving the campfire.</li><li>Common numeric inputs in the G panel, such as draw count and enemy HP, now remember the last value you entered locally instead of resetting to 1 every time.</li></ul><h2 id="v1-4-0" tabindex="-1">v1.4.0 <a class="header-anchor" href="#v1-4-0" aria-label="Permalink to &quot;v1.4.0&quot;">​</a></h2><ul><li>Multiplayer safety: most gameplay-editing tools that change cards, decks, relics, potions, resources, combat stats, enemies, and powers now use synchronized multiplayer actions instead of changing only the local client.</li><li>Multiplayer compatibility: added a Relax multiplayer lobby check toggle in Other Settings. It defaults to the safer gameplay-affecting mode. Turning it off may make mixed host/client setups easier to join, but using gameplay-editing tools in that state can still cause desyncs, disconnects, or crashes.</li><li>Hold-R room restart: added an Other Settings option to restart the current room by holding <code>R</code> for 0.3s. It is enabled by default and does not add an extra button.</li><li>Stability and diagnostics: improved Hold-R restart reliability in event rooms, improved infinite preset restore fallback behavior, and refined log output to make multiplayer troubleshooting easier.</li></ul><h2 id="v1-3-3" tabindex="-1">v1.3.3 <a class="header-anchor" href="#v1-3-3" aria-label="Permalink to &quot;v1.3.3&quot;">​</a></h2><ul><li>Mobile client compatibility hotfix.</li></ul><h2 id="v1-3-2" tabindex="-1">v1.3.2 <a class="header-anchor" href="#v1-3-2" aria-label="Permalink to &quot;v1.3.2&quot;">​</a></h2><ul><li>Added a show/hide toggle plus size and opacity customization for the floating <code>G</code> button, with persistence and runtime sync.</li><li>Fixed cases like the Architect event where an embedded combat scene could create two <code>G</code> buttons.</li><li>Added <code>Energy +5</code> and <code>Stardust +5</code>.</li><li>Added Traveler mode.</li><li>The character filter in Add Card now reads the live character card pools, so modded characters and their cards also show up there.</li><li>In true multiplayer, <code>AddCard(...)</code> now goes through a custom synchronized action instead of changing local state directly.</li><li>The event catalog now includes <code>shared ancient</code>, so shared ancient events like <code>Darv</code> can also appear in the list.</li><li>Fixed relic / potion presets saved as new presets getting lost after restarting the game.</li><li>When saving relic, potion, or custom deck presets as new presets, duplicate names now automatically get <code>-1</code>, <code>-2</code>, and so on.</li></ul><h2 id="v1-3-1" tabindex="-1">v1.3.1 <a class="header-anchor" href="#v1-3-1" aria-label="Permalink to &quot;v1.3.1&quot;">​</a></h2><ul><li>Fixed an issue where campfire options could become unclickable on some devices unless the run was advanced through event jumping.</li><li>Fixed an ancient-event flow issue that could leave the room stuck and unable to progress normally.</li><li>Reduced redundant UI rebuilds when opening Mod Config to improve responsiveness.</li></ul><h2 id="v1-3-0" tabindex="-1">v1.3.0 <a class="header-anchor" href="#v1-3-0" aria-label="Permalink to &quot;v1.3.0&quot;">​</a></h2><ul><li>Added a God Mod settings page in Mod Config so high-risk features can be disabled directly from the settings menu.</li><li>Shared settings are now kept in sync between Mod Config and the in-run G panel.</li><li>Improved relic preset editing.</li></ul><h2 id="v1-2-1" tabindex="-1">v1.2.1 <a class="header-anchor" href="#v1-2-1" aria-label="Permalink to &quot;v1.2.1&quot;">​</a></h2><ul><li>On fresh installs, <code>Ancient Refresh</code> and <code>Ancient Option Override</code> are now disabled by default, so the mod stays closer to the vanilla experience until you turn them on manually.</li><li>Fixed the Ancient-room refresh button visibility: it now hides correctly after you choose an option or leave the room.</li><li>Refined the visuals and interaction details for the settings panel and the floating <code>G</code> button, making controls clearer and easier to use.</li></ul><h2 id="v1-2-0" tabindex="-1">v1.2.0 <a class="header-anchor" href="#v1-2-0" aria-label="Permalink to &quot;v1.2.0&quot;">​</a></h2><ul><li>Added mod language switching: Follow Game, English, and Simplified Chinese.</li><li>Added relic presets and potion presets, including save, overwrite, delete, and one-click apply for default and custom presets.</li><li>Added recent-first sorting across multiple catalogs: cards, relics, potions, statuses, events, and enemies.</li><li>Improved card / status / event panel workflows, including upgraded card add, card catalog preview, status preview, and better recent item surfacing.</li><li>Improved potion management: remove the selected potion and load current potions directly into the preset editor.</li><li>Continued polish for the floating <code>G</code> button and main panel interaction: larger panel layout, more stable drag behavior, click sound feedback for the close button, and more reliable button position restore logic.</li><li>Expanded logs and troubleshooting info: startup logs include game version and enabled mod list; copied logs include mod / game version, language, platform, and enabled mod details; low-value log noise was reduced.</li><li>Cleaned up and improved ancient event refresh logic and related logs.</li><li>Fix: removed unnecessary temporary debug file output.</li></ul><h2 id="v1-1-0" tabindex="-1">v1.1.0 <a class="header-anchor" href="#v1-1-0" aria-label="Permalink to &quot;v1.1.0&quot;">​</a></h2><ul><li>Added the option to unlock all functions.</li><li>Added the &quot;Ancestors SL&quot; function.</li><li>Fixed some functions that were not working on mobile devices, such as Ancestor Refresh, Card Deletion from Fire Pit, and Setting Maximum Health Value.</li><li>Added support for viewing and copying Mod error logs, making it easier to troubleshoot issues.</li></ul><h2 id="v1-0-1" tabindex="-1">v1.0.1 <a class="header-anchor" href="#v1-0-1" aria-label="Permalink to &quot;v1.0.1&quot;">​</a></h2><ul><li>Fixed a mod compatibility issue on mobile clients.</li></ul><h2 id="v1-0-0" tabindex="-1">v1.0.0 <a class="header-anchor" href="#v1-0-0" aria-label="Permalink to &quot;v1.0.0&quot;">​</a></h2><ul><li>Completely overhauled the God Mode panel interaction, with clearer section grouping, a larger content area, and more focused access to commonly used tools.</li><li>Greatly expanded the card editor with multi-card checkbox selection, batch upgrade/downgrade actions, one-click upgrade for matching cards, and full-pile upgrade/downgrade support.</li><li>Card enchantments are no longer add-only; existing enchantments can now be edited or overwritten directly.</li><li>Improved card filtering with support for all characters, the current character, individual character groups, and colorless cards, making card search much more convenient.</li><li>Deck presets have been separated from the card editor into their own standalone section for a cleaner structure.</li><li>Relic editing now supports selecting multiple targets for batch add and batch remove operations.</li><li>Added support for extra card effects, along with a runtime patch to ensure those special effects actually take effect in play.</li><li>The floating <code>G</code> button can now be dragged freely; it only auto-snaps and hides when moved back to the screen edge, and its position is remembered.</li><li>Added a new About / Guide section with usage tips.</li><li>Enemy preview, card preview, creature drag movement, and several other interaction details have also been continuously improved.</li></ul><h2 id="v0-2-0" tabindex="-1">v0.2.0 <a class="header-anchor" href="#v0-2-0" aria-label="Permalink to &quot;v0.2.0&quot;">​</a></h2><ul><li>Feature enhancement.</li></ul><h2 id="v0-1-0" tabindex="-1">v0.1.0 <a class="header-anchor" href="#v0-1-0" aria-label="Permalink to &quot;v0.1.0&quot;">​</a></h2><ul><li>Initial release.</li></ul>',46)])])}const p=a(l,[["render",n]]);export{m as __pageData,p as default};
